window.__QUIZ_DATA__=[{"id":"objective>Mathematics>1997>1","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Express (0.0425 \u00f7 2.5) as fraction","images":[],"options":{"A":"17/10,000","B":"17/1,000","C":"17/250","D":"17/100"},"answer":"B","explanation":"0.0425\u00f72.5==>42510,000\u00f752=42510,000x25=85050,000=171,000","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>2","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"What is the log10(6.95 x 10-3)?","images":[],"options":{"A":"0.8420","B":"3.8420","C":"3 .8420","D":"3.9777"},"answer":"C","explanation":"log10(6.95 x 10-3) = log106.95 + log1010-3  = 0.8420 + (-3)log1010     (log1010 = 1)  =  3 .8420.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>3","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If P = {3, 5, 6} and Q = {4, 5, 6}, then P \u22c2 Q equals?","images":[],"options":{"A":"{3, 4}","B":"{4, 5}","C":"{4, 6}","D":"{5, 6}"},"answer":"D","explanation":"P = {3, 5, 6} and Q = {4, 5, 6}  P \u22c2 Q ==> Elements common to both P and Q  \u2234P \u22c2 Q = {5, 6}","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>4","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"A and B are two sets. The number of elements in A \u22c3 B is 49, the number in A is 22 and the number in B is 34. How many elements are in A \u22c2 B?","images":[],"options":{"A":"105","B":"27","C":"15","D":"7"},"answer":"D","explanation":"n(A \u22c3 B) = n(A) + n(B) - n(A \u22c2 B) ==> n(A \u22c2 B) = n(A) + n(B) - n(A \u22c3 B)  \u2234 n(A \u22c2 B) = 22 + 34 - 49 = 7","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>5","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGE ERROR","question":"A student found the approximate value of 0.02548 correct to two places of decimal instead of two significants. Find the percentage error?","images":[],"options":{"A":"0%","B":"131/2%","C":"155/13%","D":"20%"},"answer":"D","explanation":"0.02548 to 2 decimal places = 0.03  0.02548 to 2 significant figures = 0.025  \u2234 Error = 0.03 - 0.025 = 0.005  Percentageerror=errorexpected valuex100  =0.0050.025x100=20%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>6","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Simplify log39 + log315 - log35","images":[],"options":{"A":"log319","B":"log 3","C":"3","D":"1"},"answer":"C","explanation":"log39 + log315 - log35  = log332 + log33 x 5 - log35  = log332 + log33 x 5 - log35  = 2log33 + log33 + log35 - log35  = 2log33 + log33  = 3log33  (log33 = 1)  = 3 x 1  = 3","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>7","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Solve the equation 2/3(x + 5) = 1/4(5x - 3)","images":[],"options":{"A":"11/7","B":"18/23","C":"3","D":"7"},"answer":"D","explanation":"2/3(x + 5) = 1/4(5x - 3) (Muliply both sides by 12)    8(x + 5) = 3(5x - 3) ==> 8x + 40 = 15x - 9    49 = 7x ==> x = 7","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>8","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Which of the following equations has its roots as 4 and -5?","images":[],"options":{"A":"x2 + 4x - 20 = 0","B":"x2 + x + 20 = 0","C":"x2 - x + 20 = 0","D":"x2 + x - 20 = 0"},"answer":"D","explanation":"(x - a)(x - b) = 0  Let a = 4 and b = -5  (x - 4)(x - (-5)) = 0  (x - 4)(x + 5) = 0  x(x + 5) - 4(x + 5) = 0  x2 + 5x - 4x - 20 = 0  x2 + x - 20","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>9","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Solve the equations: 4x - y = 11; 5x + 2y = 4","images":[],"options":{"A":"x = 6, y = 13","B":"x = -2, y = -3","C":"x = -2, y = 3","D":"x = 2, y = -3"},"answer":"D","explanation":"4x - y = 11 ---- (i)  5x + 2y = 4 ---- (ii)  Multiply equation (i) by 2 and add to equ. (ii)  8x - 2y = 22  5x + 2y = 4  13x = 26  x =  2  substitute x for 2 in equ. (i)  4(2) - y = 11  8 - y = 11  8 = 11 + y  8 - 11 = y  y = -3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>10","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Makeqthesubjectoftherelationt=\u221a(pqr-r2q).","images":[],"options":{"A":"q=rt2p - r3","B":"q=t2p - r2","C":"q=rtp - r3","D":"q=p - r3rt2"},"answer":"A","explanation":"t=\u221a(pqr-r2q)  square both sides  t2=pqr-r2q  t2=q(pr-r2)  t2=q(p - r3r)  rt2=q(p-r3)  q=rt2p - r3","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>11","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"One of the roots of the equation 6x2 = 5 - 7x is ?","images":[],"options":{"A":"-1/2","B":"-1/3","C":"1/2","D":"12/3"},"answer":"C","explanation":"6x2 = 5 - 7x; 6x2 + 7x - 5 = 0    6x2 + 10x - 3x - 5 = 0    2x(3x + 5) - 1(3x + 5) = 0    (3x + 5)(2x - 1) = 0    3x + 5 = 0 or 2x - 1 = 0    3x = -5 or 2x = 1    x = -5/3 or 1/2    \u2234 1/2 is the answer","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>12","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"P varies inversely as the square of W. When W = 4, P = 9. Find the value of P when W = 9","images":[],"options":{"A":"729/16","B":"6","C":"4","D":"16/9"},"answer":"D","explanation":"P \u221d 1/W2    P = k/W2 where k is constant    9 = k/42    9 = k/16    k = 9 x 16    k = 144    P = 144/92    P = 144/81    P = 16/9","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>13","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : FUNCTIONS AND RELATIONS","question":"If x varies over the set of real numbers, which of the following is illustrated in the diagram above?","images":["data:image/png;base64,"],"options":{"A":"-2 \u2264 x","B":"-2","C":"-2","D":"-2 \u2264 x \u2264 3"},"answer":"C","explanation":"The graph indicates that x ranges between -2 and 3. But -2 and 3 are not included in the solution set since they are not shaded.  \u2234 solution ==> -2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>14","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the triangle XYZ above, XM is the altitude from X to YZ; XY = 13 cm, XZ = 15 cm and  YM = 5 cm. Find the length of YZ.","images":["data:image/png;base64,"],"options":{"A":"9 cm","B":"12 cm","C":"14 cm","D":"19.85 cm"},"answer":"C","explanation":"Using pythagoras theorem  XY2 = YM2 + MX2  132 = 52 + MX2  MX2 = 132 - 52  MX2 = 169 - 25  MX2 = 144  MX = 12 cm  In \u2206XMZ  XM2 + MZ2 = XZ2  122 + MZ2 = 152  MZ2 = 152 - 122  MZ2 = 225 - 144  MZ2 = 81  MZ = 9 cm  But YZ  = YM + MZ  \u2234 YZ = 5 + 9 = 14 cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>15","subject":"Mathematics","year":"1997","type":"Objective","topic":"MENSURATION : LONGITUDES AND LATITUDES","question":"Two points P and Q are on longitude 67oW. Their latitudes differ by 90o. Calculate their distance apart in terms of \u03c0  [Take radius of the earth = 6400 km]","images":[],"options":{"A":"6400\u03c0 km","B":"6400/\u03c0 km","C":"3200\u03c0 km","D":"3200 km"},"answer":"C","explanation":"P and Q lies on the same longitude 67oW  Latitudinal difference = 90o  \u2234Distanceapart=\u03b8360x2\u03c0R;where\u03b8=90o;R=6400km  Distance=90360x2x\u03c0x6400km  =14x2 x \u03c0 x 6400=3200\u03c0km","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>16","subject":"Mathematics","year":"1997","type":"Objective","topic":"MENSURATION : AREAS","question":"The lengths of the two parallel sides of a trapezium are 6 cm and 10 cm and the perpendicular distance between them is 5 cm. Find the area of the trapezium.","images":[],"options":{"A":"21 cm2","B":"40 cm2","C":"80 cm2","D":"150 cm2"},"answer":"B","explanation":"Area of trapezium = 1/2(a + b)h where a, b are the parallel sides and h = perpendicular distance apart    = 1/2(6 + 10)5    = 1/2(16)5    = 8 x 5    = 40 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>17","subject":"Mathematics","year":"1997","type":"Objective","topic":"MENSURATION : AREAS","question":"Calculate the total surface area of a solid cone of slant height 15 cm and base radius 8 cm in terms of \u03c0.","images":[],"options":{"A":"64\u03c0 cm2","B":"120\u03c0 cm2","C":"184\u03c0 cm2","D":"200\u03c0 cm2"},"answer":"C","explanation":"T.S.A of cone = \u03c0r2 + \u03c0rl = \u03c0r(r + l)  = \u03c0 x 8(8 + 15)  = 8\u03c0(23)  = 184\u03c0 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>18","subject":"Mathematics","year":"1997","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The cross section of a prism is a right angled triangle 3 cm by 4 cm by 5 cm. The height of the prism is 8 cm. Calculate its volume.","images":[],"options":{"A":"48 cm3","B":"60 cm3","C":"96 cm3","D":"120 cm3"},"answer":"A","explanation":"Area of prism = Ah where A = base area, h = height  A = 1/2 x 3 x 4 = 6 cm2  V = A x h = 6 x 8 = 48 cm3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>19","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"Find the radius of a circle in which an arc of length 44 cm subtends angle 200o at the centre of the circle.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"3.9 cm","B":"12.6 cm","C":"25.2 cm","D":"38.4 cm"},"answer":"B","explanation":"\u2234l=\u03b8360x2\u03c0r  44=200360x2x227xr  44=8800r2520  110880 = 8800r    r=1108808800  r = 12.6 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>20","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"The diagram is a triangle XYZ whose area is 23.5 cm2. XY = 10 cm and YZ = 8 cm, calculate \u03b8, correct to nearest degree.","images":["data:image/png;base64,"],"options":{"A":"34o","B":"35o","C":"36o","D":"37o"},"answer":"C","explanation":"Area = 23.5 cm2    Area = 1/2 ab sin \u03b8    1/2 x 8 x 10 x sin \u03b8 = 23.5    40 x sin \u03b8 = 23.5    sin \u03b8 = 23.5/40    \u03b8 = sin-1 0.5875    \u03b8 = 35.98o    \u03b8 = 36o (to the nearest degree)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>21","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : CONSTRUCTION","question":"Which of the following is not necessarily sufficient for the construction of a triangle?","images":[],"options":{"A":"Three sides","B":"Two sides and an included angle","C":"Two sides and a right angle","D":"Two sides and an angle"},"answer":"C","explanation":"To construct a triangle one should know these properties and rules: All three sides are given (SSS \u2013 Side side side) Two sides and included angle are given (SAS \u2013 Side angle side) Two angles and the included side is given (ASA \u2013 Angle side angle) and when the  hypotenuse side and any one of the other two sides of right triangle are given.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>22","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, EF||QR, PE = 2 cm, EQ = 4 cm and FR = 6 cm. Find x?","images":["data:image/png;base64,"],"options":{"A":"2 cm","B":"3 cm","C":"4 cm","D":"5 cm"},"answer":"B","explanation":"Tocalculatex.Useratio==>x2=x + 62 + 4==>x2=x + 66  Since EF is parallel to QR; 6x = 2x + 12    4x = 12    x = 3 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>23","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Which of the following statements is/are true when two straight lines intersects?  i. Adjacent angles are equal  ii. Vertically opposite angles are equal  iii. Adjacent angles are supplementary","images":[],"options":{"A":"II only","B":"I and II only","C":"I and III only","D":"II and III only"},"answer":"D","explanation":"When two lines intersect as shown:  (i) \u2220AOY is adjacent to \u2220YOB  (ii) \u2220AOX is vertically opposite to \u2220YOB  For all intersecting straight lines:  Statements (ii) and (iii) are always true but (i) is only true when they are at right angle to each other.  (ii) and (iii) are right","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>24","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"PQRS and GHRS are parallelograms on the same base SR and between the same parallel straight lines PH and SR. Which of the following is true?","images":["data:image/png;base64,"],"options":{"A":"\u2206 PGS = \u2206 QHR","B":"Parallelogram PQRS = \u2206 QHR","C":"Trapezium PQXS = \u2206 QHR","D":"Parallelogram PQRS = Parallelogram GHRS"},"answer":"D","explanation":"Parallelograms on the same base and within same parallel are equal in area  \u2234 Parallelogram PQRS is equal to Parallelogram GHRS","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>25","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"From the diagram which of the following is true?","images":["data:image/png;base64,"],"options":{"A":"a + b + x = 180o","B":"a = b + x","C":"a - b = 180o - x","D":"a + b = x + 180o"},"answer":"D","explanation":"Adjacent angle to a = (180o - a) (angle on a straight line = 180o)  Adjacent angle to b = (180o - b) (angle on a straight line = 180o)  \u2234 x + (180o - a) + (180o - b) = 180o (sum of angles in a triangle)  \u2234 x + 360o - a - b = 180o; x - a - b + 180o = 0  \u2234 a + b = x + 180o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>26","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The interior angles of a pentagon are 126o, 114o, y, 92o and 83o. Find the value of y?","images":[],"options":{"A":"85o","B":"95o","C":"105o","D":"125o"},"answer":"D","explanation":"sum of interior angles of pentagon  = (2n - 4)90o; where n = 5 ==> [2(5) - 4]90o = 6 x 90o = 540o  540o = 126o + 114o + yo + 92o + 83o.  \u2234 540o = 415o + yo  \u2234 y = 125o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>27","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solve the inequality 3x - 8 \u2265 5x","images":[],"options":{"A":"x \u2264 4","B":"x \u2265 1","C":"x \u2264 -4","D":"x \u2264 -1"},"answer":"C","explanation":"3x - 8 \u2265 5x   Collect like terms  -8 \u2265 5x - 3x  -8 \u2265 2x  x \u2264 -4","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>28","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Divide  3 .6721 by 4","images":[],"options":{"A":"0.9180","B":"1 .4180","C":"1 .1680","D":"1 .1682"},"answer":"B","explanation":"Divide3.6721by4==> 4  + 1.67214= 4 4+1.67214=  1 .4180","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>29","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"The eleventh term of an A.P is 25 and its first term is -3. Find its common difference.","images":[],"options":{"A":"19/10","B":"21/5","C":"23/11","D":"24/5"},"answer":"D","explanation":"T = a + 10d = 25; a = -3 \u2234 -3 + 10d = 25  10d = 25 + 3 = 28  d = 28/10 = 24/5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>30","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Find the common ratio in the G.P log3, log9, log81,...","images":[],"options":{"A":"1","B":"2","C":"3","D":"6"},"answer":"B","explanation":"commonratio(r)=T2T1orT3T2  r=log9log3=log32log3=2log3log3=2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>31","subject":"Mathematics","year":"1997","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Find the value of t for which 64/27 = (3/4)t - 1","images":[],"options":{"A":"-4","B":"-2","C":"11/3","D":"2"},"answer":"B","explanation":"6427=(3/4)t - 1==>4333= (3/4)t - 1  = (4/3)3 = (3/4)t - 1    = (3/4)-3 = (3/4)t - 1    Equate the powers    -3 = t - 1    t = -2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>32","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"O is the centre of the circle PQRS. PR and QS intersect at T. POR is a diameter, \u2220PQT = 42o and \u2220QTR = 64o. Find \u2220QRT.","images":["data:image/png;base64,"],"options":{"A":"68o","B":"64o","C":"42o","D":"32o"},"answer":"A","explanation":"\u2220PQR = 90o (angle in a semi circle is a right angle)  \u2234 \u2220RQT = 90o - 42o = 48o  From \u2206QRT  \u2220QRT + \u2220RQT + \u2220QTR = 180o (sum of angles in a triangle)  \u2220QRT + 48o + 64o = 180o  \u2220QRT + 112o = 180o  \u2220QRT = 180o - 112o  \u2220QRT = 68o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>33","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"TR is the tangent to the circle PQR. With centre O. Find the size of \u2220PRT","images":["data:image/png;base64,"],"options":{"A":"44o","B":"46o","C":"60o","D":"74o"},"answer":"C","explanation":"Construction: Join  OP  \u2234 OP  =  OQ   (Radii)  \u2234 \u2220OPR = \u2220PRO = 30o (base angle of isosceles triangle)  OP = OR  But \u2220ORT = 90o (the radius meet the tangent at a right angle)  \u2220ORP = 30o, \u2220PRT + 30o = 90o ==> \u2220PRT = 60o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>34","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Two angles of a triangle are 41o and 49o. Which of the following is true? It is","images":[],"options":{"A":"An equilateral triangle","B":"An isosceles triangle","C":"A triangle with an obtuse angle","D":"A right angled triangle"},"answer":"D","explanation":"Two angles given as 41o and 49o  \u2234 Third angle ==> 180o - (41o + 49o) = 180o - 90o = 90o.  Since the three angles of the triangle are 41o, 49o, 90o, the triangle is a right angled triangle","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>35","subject":"Mathematics","year":"1997","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Given that 1/2log10P =1, find the value of P","images":[],"options":{"A":"104","B":"103","C":"102","D":"101"},"answer":"C","explanation":"1/2log10P = 1; log10P = 2 ==> P = 102  (Recall if logax  = n \u2234 an = x)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>36","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"If two triangles are similar, which of the following is true? Their","images":[],"options":{"A":"corresponding sides are equal","B":"corresponding angles are equal","C":"corresponding altitudes are equal","D":"Areas are equal"},"answer":"B","explanation":"Two congruent triangles are equal in all respect but two similar triangles may be bigger than each other but their angles will be equal.  Similar triangles are equiangular ==> corresponding angles are equal or corresponding sides are in the same ratio.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>37","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Which of the following is not necessarily true of a rectangle","images":[],"options":{"A":"The diagonals are equal","B":"The diagonals bisect each other","C":"The diagonals are perpendicular","D":"Each diagonal divides the area of the rectangle equally"},"answer":"C","explanation":"All rectangle has:  (i) Equal diagonals  (ii) Diagonal bisecting area equally  (iii) Diagonals bisecting each other  (iv) Diagonal dividing the rectangle into 2 congruent triangles.  A plane shape in which the diagonals are perpendicular is the rhombus","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>38","subject":"Mathematics","year":"1997","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"A chord is 5 cm from the centre of a circle of diameter 26 cm. Find the length of the chord?","images":[],"options":{"A":"16 cm","B":"18 cm","C":"24 cm","D":"25.51 cm"},"answer":"C","explanation":"Distsnce of chord from centre = 5 cm  Diameter of circle = 26 cm; Radius = 13 cm  Length of chord = ?  O = centre  PQ = chord = (2x) cm  Using pythagoras theorem  x2 + 52 = 132  x2 = 132 - 52  x2 = 169 - 25  x2 = 144  x = 12 cm  \u2234 Length of chord = 2 x 12 = 24 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>39","subject":"Mathematics","year":"1997","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"The angle of elevation of a point T on a tower from a point U  on the horizontal ground is 30o. If TU = 54 m, how high is T above the horizontal ground?","images":[],"options":{"A":"108 m","B":"72 m","C":"46.3 m","D":"27 m"},"answer":"D","explanation":"Let x represent the height T of the tower.  UsingsinQ=opphyp  \u2234sin30=x54==>54sin30=x  Butsin30=12\u2234 x=54x12=27m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>40","subject":"Mathematics","year":"1997","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"Express the true bearing of 250o as a compass bearing.","images":[],"options":{"A":"N20oE","B":"S20oE","C":"N20oW","D":"S70oW"},"answer":"D","explanation":"250o lies in the south west direction  250o = 270o - 20o or 250o = 180o + 70o  250o = S70oW","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>41","subject":"Mathematics","year":"1997","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If sin \u03b8 = -1/2, find all the values of \u03b8 between 0 and 360o?","images":[],"options":{"A":"120o, 180o","B":"120o, 240o","C":"210o, 300o","D":"210o, 330o"},"answer":"D","explanation":"sin \u03b8 = -1/2  \u03b8 = sin-1 (-0.5)  \u03b8 = -30o  Since sine is negative in the 3rd and 4th Quadrants  ==> 180o + 30o = 210o and 360o - 30o = 330o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>42","subject":"Mathematics","year":"1997","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"cos 65o has the same value as","images":[],"options":{"A":"sin 65o","B":"cos 25o","C":"cos 115o","D":"cos 295o"},"answer":"D","explanation":"65o ==> acute angle; cos 65o = positive ==> 1st Quadrant  Cosine as a trigonometric function is positive both in 1st and 4th Quadrant  \u2234 cos 65o = cos (360o - 65o) = cos 295o","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>43","subject":"Mathematics","year":"1997","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Two sides of a triangle are perpendicular if the two sides are 8 cm and 6 cm, calculate, correct to the nearest degree, the smallest angle of the triangle?","images":[],"options":{"A":"35o","B":"36o","C":"37o","D":"38o"},"answer":"C","explanation":"Two sides of a triangle are perpendicular.  \u2234 The triangle is a right-angled triangle.  Using pythagoras theorem  x2 = 82 + 62  x2 = 64 + 36  x2 = 100  x = 10 cm  In a triangle, the largest side faces the largest angle.  \u2234 the smallest side faces the smallest angle.  Hence,sin\u03b8=610=0.6\u2234\u03b8=sin-10.6=36.87o  \u03b8 = 37o (to the nearest degree)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>44","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The graph is the cumulative frequency curve for the weight distribution of 100 workers in a factory. Which of the points P.Q.R.S and T indicates the median weight?","images":["data:image/png;base64,"],"options":{"A":"T","B":"S","C":"R","D":"Q"},"answer":"D","explanation":"The median age is the 50th percentile i.e the weight that lies averagly in the centre.  The median weight therefore will lie on the weight axis;  On the illustration graph, median P = Q","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1997>45","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The pie chart represents the fruit on display in a grocery shop. If there are 60 oranges on display, how many apples are there?","images":["data:image/png;base64,"],"options":{"A":"40","B":"80","C":"90","D":"120"},"answer":"C","explanation":"Sectorial angle for orange = 360o - (60o + 100o + 120o) = 360o - 280o = 80o  Number of oranges = 60; Let there be x apples.  \u2234x120o=6080o==>x=60 x 120o80o=90","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>46","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Calculate the standard deviation of the numbers 2, 5, 6, 4 and 8?","images":[],"options":{"A":"2","B":"4","C":"6","D":"7"},"answer":"A","explanation":"S.D = \u221a\u2211d2/n    d = x - mean    mean = \u2211n/n    mean = 2 + 5 + 6 + 4 +85 = 5    S.D = \u221a(2 - 5)2 + (5 - 5)2 + (6 - 5)2 + (4 - 5)2 + (8 - 5)25  S.D = \u221a9 + 0 + 1 + 1 + 95  S.D = \u221a205  S.D = \u221a4    \u2234 S.D = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>47","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The table shows the scores of a group of students in a test;  scores 1 2 3 4 5 6No of students 1 4 5 6 x 2  If the average score is 3.5, find the value of x?","images":[],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"B","explanation":"Average score = \u2211fx\u2211f = (1 x 1) + (2 x 4) + (3 x 5) + (4 x 6) + (6 x 2) + (5 x x)18 + x  \u2234 3.5 = 1 + 8 + 15 + 24 + 5x + 1218 + x ==> 3.5 = 60 + 5x18 + x  \u2234 3.5(18 + x) = 60 + 5x; 63 + 3.5x = 60 + 5x    3 = 1.5x    x = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>48","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"What is the probability of having an odd number in a single throw of fair die with the faces numbered 1, 2, 3, 4, 5 and 6?","images":[],"options":{"A":"5/6","B":"2/3","C":"1/2","D":"1/3"},"answer":"C","explanation":"Possible outcomes ==> 1, 2, 3, 4, 5, 6 ==> Total = 6  No of odd ==> 1, 3, 5 ==> Total = 3  Pr(oddnumber)=favourable outcomeTotal possible outcome=36=12","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1997>49","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Colour of ball Red Black GreenNo of occurrences 54 30 16  A bag contains red, black and green identical balls. A ball is picked and replaced. The table shows the result of 100 trials. Find the experimental probability of picking a green ball.","images":[],"options":{"A":"16","B":"21/25","C":"1/3","D":"4/25"},"answer":"D","explanation":"Total no of trials = 54 + 30 + 16 = 100  No of green balls = 16 ==> favourable outcome  \u2234Experimentalprobabilityofpickinggreenball=16100=425","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1997>50","subject":"Mathematics","year":"1997","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A bag contains 3 white, 6 red and 5 blue identical balls. A ball is picked at random from the bag. What is the probability that it is either white or blue?","images":[],"options":{"A":"9/14","B":"4/7","C":"3/7","D":"5/14"},"answer":"B","explanation":"3 white balls, 6 red balls, 5 blue balls. Total =14 balls  Probabilityofpickingeitherwhiteorblue=P(W)+P(B)=314+514=814=47","marks":"1","difficulty":"2"}];